 3→import com.alibaba.excel.util.StringUtils;
 4→import org.redisson.Redisson;
 5→import org.redisson.api.RedissonClient;
 6→import org.redisson.config.Config;
 7→import org.springframework.beans.factory.annotation.Value;
 8→import org.springframework.context.annotation.Bean;
 9→import org.springframework.context.annotation.Configuration;
10→
11→@Configuration
12→public class RedissonConfig {
13→
14→    @Value("${spring.data.redis.password}")
15→    private String password;
16→    @Value("${spring.data.redis.host}")
17→    private String host;
18→    @Value("${spring.data.redis.port}")
19→    private String port;
20→
21→    /**
22→     * 对 Redisson 的使用都是通过 RedissonClient 对象
23→     * @return
24→     */
25→    @Bean(name = "redissonClient", destroyMethod = "shutdown") // 服务停止后调用 shutdown 方法
26→    public RedissonClient redissonClient() {
27→        // 1、创建配置
28→        Config config = new Config();
29→
30→        // 2、集群模式
31→        // config.useClusterServers().addNodeAddress("127.0.0.1:7004", "127.0.0.1:7001");
32→        config.useSingleServer()
33→                .setPassword(StringUtils.isEmpty(password) ? null : password)
34→                .setAddress(host.contains("://") ? "" : "redis://" + host + ":" + port);
35→        return Redisson.create(config);
36→    }
37→
38→}
